import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.Culc7SYV.js";const u=JSON.parse('{"title":"Multiple Choice Questions","description":"","frontmatter":{},"headers":[],"relativePath":"Multiple-Choice-Questions.md","filePath":"Multiple-Choice-Questions.md","lastUpdated":1772690052000}'),s={name:"Multiple-Choice-Questions.md"};function n(r,e,l,d,c,p){return t(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="multiple-choice-questions" tabindex="-1">Multiple Choice Questions <a class="header-anchor" href="#multiple-choice-questions" aria-label="Permalink to &quot;Multiple Choice Questions&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>MCQ cards show one question with multiple options. You choose one answer.</p><h2 id="mcq-format" tabindex="-1">MCQ Format <a class="header-anchor" href="#mcq-format" aria-label="Permalink to &quot;MCQ Format&quot;">​</a></h2><p>Use <code>MCQ</code> for the question stem, <code>A</code> for the correct answer, and <code>O</code> for each incorrect option:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T | French Capitals |</span></span>
<span class="line"><span>MCQ | What is the capital of France? |</span></span>
<span class="line"><span>A | Paris |</span></span>
<span class="line"><span>O | London |</span></span>
<span class="line"><span>O | Berlin |</span></span>
<span class="line"><span>O | Madrid |</span></span>
<span class="line"><span>I | Remember: it&#39;s on the Seine |</span></span>
<span class="line"><span>G | Geography |</span></span></code></pre></div><ul><li><code>MCQ</code>: required question stem.</li><li><code>A</code>: required correct answer (one).</li><li><code>O</code>: required incorrect options (one or more).</li></ul><h2 id="modal-steps" tabindex="-1">Modal Steps <a class="header-anchor" href="#modal-steps" aria-label="Permalink to &quot;Modal Steps&quot;">​</a></h2><ol><li>Right-click in a note → <strong>Add flashcard → MCQ Card</strong>.</li><li>Enter the question stem.</li><li>Enter the correct answer.</li><li>Add incorrect options (click <strong>Add option</strong> for more).</li><li>Optionally add title, info, and groups.</li><li>Click <strong>Save</strong>.</li></ol><h2 id="review-flow" tabindex="-1">Review Flow <a class="header-anchor" href="#review-flow" aria-label="Permalink to &quot;Review Flow&quot;">​</a></h2><p>During review, options are shown as buttons. Select one option.</p><ul><li>Correct: selected option turns green, grade is <strong>Good</strong>.</li><li>Incorrect: selected option turns red, correct option is highlighted, grade is <strong>Again</strong>.</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>MCQ grading is automatic. You do not press a separate grade button.</p></div><h3 id="option-shuffle" tabindex="-1">Option Shuffle <a class="header-anchor" href="#option-shuffle" aria-label="Permalink to &quot;Option Shuffle&quot;">​</a></h3><p>By default, options stay in the order you wrote. Enable <strong>Randomise MCQ options</strong> in Settings -&gt; Study to shuffle order each time.</p><h2 id="grading" tabindex="-1">Grading <a class="header-anchor" href="#grading" aria-label="Permalink to &quot;Grading&quot;">​</a></h2><p>MCQs are <strong>auto-graded</strong> based on your selection:</p><table tabindex="0"><thead><tr><th>Your choice</th><th>Grade applied</th></tr></thead><tbody><tr><td>Correct option</td><td><strong>Good</strong></td></tr><tr><td>Incorrect option</td><td><strong>Again</strong></td></tr></tbody></table><p>The FSRS scheduler then updates the card&#39;s scheduling data based on the grade, just like any other card type. See <a href="./Grading">Grading</a> for more on how grading works.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Write plausible distractors (wrong options) — if options are obviously wrong, the card isn&#39;t testing real knowledge.</li><li>Use MCQs for topics where distinguishing between similar items is the learning goal.</li><li>Combine with the <code>I</code> field to explain why the correct answer is right.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Creating-Cards">Creating Cards</a></li><li><a href="./Grading">Grading</a></li></ul>`,24)])])}const g=a(s,[["render",n]]);export{u as __pageData,g as default};
